mapper.select:
SELECT i.response_id AS response_id, i.question_id AS question_id, q.question_text AS question_text, q.question_type AS question_type,
/* 멀티/싱글 선택지: 질문 단위로 합치기 */ GROUP_CONCAT(c.choice_text ORDER BY c.display_order SEPARATOR ', ') AS choice_text,
/* TEXT */ MAX(i.answer_text) AS answer_text,
/* STAR/NUMBER */ MAX(i.answer_number) AS answer_number,
/* created_at은 대표값 하나만 */ MAX(i.created_at) AS created_at
FROM survey_response_item i JOIN survey_question q ON q.question_id = i.question_id LEFT JOIN survey_choice c ON c.choice_id = i.choice_id WHERE i.response_id = #{responseId}
GROUP BY i.response_id, i.question_id, q.question_text, q.question_type
ORDER BY q.display_order ASC, i.question_id ASC

SELECT COUNT(*)
FROM survey_response
WHERE survey_id = #{surveyId}
  AND member_id = #{memberId}

SELECT response_id
FROM survey_response
WHERE survey_id = #{surveyId}
  AND member_id = #{memberId}
LIMIT 1

mapper.update:
UPDATE survey_response
SET updated_at = NOW()
WHERE response_id = #{responseId}

mapper.select:
SELECT COUNT(*)
FROM survey_choice
WHERE choice_id = #{choiceId}
  AND question_id = #{questionId}

SELECT COUNT(*)
FROM survey_response
WHERE survey_id = #{surveyId}
